import{_ as i,o as s,c as t,a6 as r,jv as a,jw as l,jx as o,jy as n,jz as e,jA as g,iE as _,iF as m,iG as c,iH as d,jB as h,jC as x,iJ as f}from"./chunks/framework.UYVGz2W_.js";const T=JSON.parse('{"title":"毎日および毎週のレビュー","description":"","frontmatter":{},"headers":[],"relativePath":"ja/review-weekly/index.md","filePath":"ja/review-weekly/index.md"}'),u={name:"ja/review-weekly/index.md"};function j(A,p,k,w,v,P){return s(),t("div",null,[...p[0]||(p[0]=[r('<h1 id="毎日および毎週のレビュー" tabindex="-1">毎日および毎週のレビュー <a class="header-anchor" href="#毎日および毎週のレビュー" aria-label="Permalink to “毎日および毎週のレビュー”">​</a></h1><p>毎日または毎週のレビュー用に、<strong>プレイリスト</strong>を作成することができます。</p><h2 id="社内レビュー用にプレイリストを作成する" tabindex="-1">社内レビュー用にプレイリストを作成する <a class="header-anchor" href="#社内レビュー用にプレイリストを作成する" aria-label="Permalink to “社内レビュー用にプレイリストを作成する”">​</a></h2><p>ドロップダウンメニューに<strong>プレイリスト</strong>ページがあります。</p><p><img src="'+a+'" alt="プレイリストメインメニュー"></p><p><strong>プレイリスト</strong>ページは2つの部分に分かれています。</p><p>(1) プレイリストを作成したり、既存のプレイリストを読み込むことができるプレイリストリスト。 (2) 最後に作成したプレイリストと最後に変更したプレイリスト</p><p><img src="'+l+'" alt="プレイリストページ"></p><p>まず、<strong>プレイリスト</strong>を作成します <img src="'+o+'" alt="プレイリスト追加ボタン">。デフォルトの名前は デフォルト名は日付と時刻です。すぐに変更できます。プレイリストを スタジオまたはクライアントと共有するか、また、ショットまたはアセットのプレイリストにするかを選択できます。 プレイリストにタスクタイプのタグを追加することもできます。</p><p><img src="'+n+'" alt="プレイリスト追加ページ"></p><p>プレイリストが作成されると、検索/フィルタバーから、プレイリストに追加するショットを選択することができます。</p><p>また、<strong>ムービー全体を追加</strong>することもでき、ムービー内のすべてのショットが追加されます。</p><p><strong>デイリー保留中</strong>を選択すると、その日の<strong>WFA</strong>タスクがすべて追加されます。</p><p>特定のシーケンスのみに焦点を当てたい場合は、<strong>シーケンス全体を追加</strong>することもできます。</p><p>グローバルショット/アセットページと同じ<strong>フィルタ</strong>を使用できます。例えば、すべてを選択するには、 WFAはアニメーションステージの略です。 検索バーに<strong>animation=wfa</strong>と入力します。<strong>Add selection</strong>ボタンで選択を確定します。 Kitsuは、<strong>Animation</strong>ステージで<strong>WFA</strong>ステータスを持つショットを選択します。それでも、Kitsuは自動的に<strong>最新のアップロードバージョン</strong>を読み込みます。</p><p>ショットは画面の上部に表示されます。 すべての変更は 自動的に保存されます。</p><p><img src="'+e+'" alt="プレイリストページ"></p><h2 id="レビューと検証" tabindex="-1">レビューと検証 <a class="header-anchor" href="#レビューと検証" aria-label="Permalink to “レビューと検証”">​</a></h2><p>プレイリストを作成すると、いくつかのオプションが利用可能になります。</p><p><img src="'+g+'" alt="プレイリスト全体"></p><ul><li><p>再生または一時停止</p></li><li><p>要素から要素への移動</p></li><li><p>選択した要素の位置を全要素数と比較して表示</p></li><li><p>サウンドのミュートまたはミュート解除</p></li><li><p>速度変更、2倍速（x2）、通常速度（x1）、半分の速度（x0.50）、4分の1の速度（x0.25）</p></li><li><p>1つの要素をループ再生</p></li><li><p>サウンド波形の表示</p></li><li><p>再生中の注釈の表示</p></li><li><p>プレイリスト全体の時間コードに対する要素の時間コード</p></li><li><p>フレーム数</p></li><li><p>プレビューでフレーム単位の移動。キーボードの矢印キーでも移動できます。</p></li><li><p>比較ツール</p></li><li><p>描画コメントの取り消しとやり直しオプション</p></li><li><p>テキストと描画オプション、選択した項目の削除</p></li></ul><p>の選択と削除</p><ul><li>プレイリストのすべての要素のタスクタイプの変更</li><li>コメントセクションの表示</li><li>プレイリストの要素の非表示</li><li>LD（低解像度）からHD（高解像度）への切り替え</li><li>すべての分割された要素を含む<strong>Zip</strong>ファイル、<strong>.csv</strong>テキストファイル、または<strong>Build .mp4</strong>（ショットのみ）としてプレイリストをダウンロードして、ムービー全体を作成する</li><li>フルスクリーン</li></ul><p>プレイリスト化されたショット/アセットごとに、表示する<strong>タスク</strong>と <strong>バージョン</strong>を選択できます。</p><p><img src="'+_+'" alt="プレイリストのタスク選択"><img src="'+m+'" alt="プレイリストのバージョン選択"></p><p>また、ショットの2つのタスクを並べて表示することもできます。</p><p>比較] ボタンをクリックします <img src="'+c+'" alt="比較ボタン"> し、2 番目のタスクタイプを選択します。</p><p><img src="'+d+'" alt="プレイリストを並べて表示"></p><p>プレイリストの主な目的は、ショットやアセットの確認を支援することです。</p><p>プレビューから直接ショットにコメントを追加できます。</p><p>コメント**ボタンをクリックします。</p><p><img src="'+h+'" alt="プレイリストのコメント"></p><p>右パネルにアクセスできるようになりました。このパネルには、コメントの履歴とそのステータスが表示されます。</p><p>ビデオ上の描画コメント（タイムラインの下の赤い点）を見ることができます。</p><p><img src="'+x+'" alt="プレイリストのコメント"></p><p><strong>描画</strong>ボタンをクリックすると、ビデオ上に描画したり文字を入力したりすることができます。<img src="'+f+'" alt="描画ボタン"></p>',36)])])}const S=i(u,[["render",j]]);export{T as __pageData,S as default};
